import{_ as t,c as o,e as i,a as n,o as r,r as a}from"./app.1a8a17f8.js";const y=JSON.parse('{"title":"Why do I write blogs","description":"","frontmatter":{},"headers":[{"level":2,"title":"To practice English writing","slug":"to-practice-english-writing","link":"#to-practice-english-writing","children":[]},{"level":2,"title":"To self query conveniently","slug":"to-self-query-conveniently","link":"#to-self-query-conveniently","children":[]},{"level":2,"title":"To monitor the quality of life","slug":"to-monitor-the-quality-of-life","link":"#to-monitor-the-quality-of-life","children":[]},{"level":2,"title":"Summary","slug":"summary","link":"#summary","children":[]}],"relativePath":"meditation/why-do-I-write-blogs.md","lastUpdated":1670652927000}'),s={name:"meditation/why-do-I-write-blogs.md"},l=n('<h1 id="why-do-i-write-blogs" tabindex="-1">Why do I write blogs <a class="header-anchor" href="#why-do-i-write-blogs" aria-hidden="true">#</a></h1><p>When I was in university, I started to write a blog, hoping to make a good impression on the interviewer when I was looking for a job.</p><p>I got what I wanted, but also lost the reason to write a blog.</p><p>I tried to keep blogging, but failed. Because it took me a long time to write a blog, but nobody read my blog at all.</p><p>This situation did not improve untill I found other reasons to write blogs.</p><p>Here are the reasons I found for blogging.</p><h2 id="to-practice-english-writing" tabindex="-1">To practice English writing <a class="header-anchor" href="#to-practice-english-writing" aria-hidden="true">#</a></h2><p>As a Chinese, my English is very poor. But as a programmer, I need to have a high level of English. So I decided to use blogging to improve my English.</p><p>To my surprise, I found that I prefer to write short articles in English, because the articles will have more words and look more beautiful.</p><p>I hope to write more essays in the future.</p><h2 id="to-self-query-conveniently" tabindex="-1">To self query conveniently <a class="header-anchor" href="#to-self-query-conveniently" aria-hidden="true">#</a></h2><p>I have a lot of things to look up in my work, but I can&#39;t remember so many things, and the search engine may not be able to find answers I need.</p><p>After softing these things into blogs, I can use the search engine inside the blog to check my past solutions.</p><h2 id="to-monitor-the-quality-of-life" tabindex="-1">To monitor the quality of life <a class="header-anchor" href="#to-monitor-the-quality-of-life" aria-hidden="true">#</a></h2><p>There is no doubt that blogging is a time consuming and energy consuming thing. Only when my life is good, can I publish articles stably and efficiently.</p><p>As long as I observe that I haven&#39;t written a blog for a period of time, I will seriously consider whether there is something wrong with my life.</p><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-hidden="true">#</a></h2><p>In a word, I write blogs for myself, not for others. That&#39;s why I keep writing blogs.</p>',18);function h(d,g,c,m,p,u){const e=a("Comment");return r(),o("div",null,[l,i(e,{id:1})])}const w=t(s,[["render",h]]);export{y as __pageData,w as default};
